namespace sv_13d4f10bee9c45d2accc631cce583881.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service — one instance per circuit (per user).
/// Holds theme state and notifies all subscribers on change.
/// </summary>
public sealed class ThemeService
{
    private ThemeMode _theme = ThemeMode.System;
    private string _accentColor = "#0d6efd";

    public ThemeMode Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    /// <summary>
    /// Raised whenever Theme or AccentColor changes.
    /// Interactive components subscribe to this to re-render.
    /// </summary>
    public event Action? OnThemeChanged;

    private void NotifyChanged() => OnThemeChanged?.Invoke();
}

@* Interactive island embedded in the static layout *@
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable
@using sv_13d4f10bee9c45d2accc631cce583881.Services

<span class="theme-indicator" style="color: @ThemeService.AccentColor;" title="Current theme">
    @GetIcon() @ThemeService.Theme
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnThemeChanged += HandleThemeChanged;
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private string GetIcon() => ThemeService.Theme switch
    {
        ThemeMode.Dark => "🌙",
        ThemeMode.Light => "☀️",
        _ => "💻"
    };

    public void Dispose()
    {
        ThemeService.OnThemeChanged -= HandleThemeChanged;
    }
}

@* Interactive island for quick theme switching (placed in sidebar/nav) *@
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable
@using sv_13d4f10bee9c45d2accc631cce583881.Services

<button class="btn btn-sm btn-outline-light mt-2" @onclick="CycleTheme"
        title="Toggle theme">
    @GetIcon()
</button>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnThemeChanged += HandleThemeChanged;
    }

    private void CycleTheme()
    {
        ThemeService.Theme = ThemeService.Theme switch
        {
            ThemeMode.Light => ThemeMode.Dark,
            ThemeMode.Dark => ThemeMode.System,
            _ => ThemeMode.Light
        };
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private string GetIcon() => ThemeService.Theme switch
    {
        ThemeMode.Dark => "🌙",
        ThemeMode.Light => "☀️",
        _ => "💻"
    };

    public void Dispose()
    {
        ThemeService.OnThemeChanged -= HandleThemeChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable
@using sv_13d4f10bee9c45d2accc631cce583881.Services

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="btn-group mb-3" role="group">
            @foreach (var mode in Enum.GetValues<ThemeMode>())
            {
                <button class="btn @(ThemeService.Theme == mode ? "btn-primary" : "btn-outline-primary")"
                        @onclick="() => ThemeService.Theme = mode">
                    @mode
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>

        <div class="d-flex align-items-center gap-2 mb-3">
            <input type="color" class="form-control form-control-color"
                   value="@ThemeService.AccentColor"
                   @onchange="OnAccentChanged" />
            <span style="color: @ThemeService.AccentColor; font-weight: bold;">
                @ThemeService.AccentColor
            </span>
        </div>

        <p class="text-muted small mb-0">
            Changes apply instantly to all components — check the header indicator.
        </p>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnThemeChanged += HandleThemeChanged;
    }

    private void OnAccentChanged(ChangeEventArgs e)
    {
        ThemeService.AccentColor = e.Value?.ToString() ?? "#0d6efd";
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnThemeChanged -= HandleThemeChanged;
    }
}

